diff --git a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
index 0633388cd411..532ebb147ac7 100644
--- a/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
+++ b/llvm/lib/Transforms/InstCombine/InstCombineSelect.cpp
@@ -3130,6 +3130,64 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 1, TrueSI->getTrueValue());
         return &SI;
       }
+      // select(select C0, true, C1), select(C0, A, B), C ->
+      //   select C0, A, (select C1, B, C)
+      // Variations with inverted conditions are handled.
+      if (auto *CondSI = dyn_cast<SelectInst>(CondVal))
+        if (match(CondSI->getTrueValue(), m_One()) &&
+            (CondSI->hasOneUse() || TrueSI->hasOneUse())) {
+          Value *InnerCond = CondSI->getCondition();
+          Value *TrueCond = TrueSI->getCondition();
+          Value *CommonCond = nullptr;
+          bool InvertedInCond = false;
+          bool InvertedInTrue = false;
+          if (InnerCond == TrueCond) {
+            CommonCond = InnerCond;
+          } else if (match(InnerCond, m_Not(m_Specific(TrueCond)))) {
+            CommonCond = TrueCond;
+            InvertedInCond = true;
+          } else if (match(TrueCond, m_Not(m_Specific(InnerCond)))) {
+            CommonCond = InnerCond;
+            InvertedInTrue = true;
+          } else {
+            Value *X, *Y;
+            if (match(InnerCond, m_Not(m_Value(X))) &&
+                match(TrueCond, m_Not(m_Value(Y))) && X == Y) {
+              CommonCond = InnerCond;
+            }
+          }
+          if (CommonCond) {
+            Value *InnerSel;
+            Value *TrueResult, *FalseResult;
+            if (!InvertedInCond && !InvertedInTrue) {
+              // select(select C0, true, C1), select(C0, A, B), C -> select C0, A, (select C1, B, C)
+              InnerSel = Builder.CreateSelect(CondSI->getFalseValue(),
+                                              TrueSI->getFalseValue(), FalseVal);
+              TrueResult = TrueSI->getTrueValue();
+              FalseResult = InnerSel;
+            } else if (InvertedInCond && !InvertedInTrue) {
+              // select(select not(C0), true, C1), select(C0, A, B), C -> select C0, (select C1, A, C), B
+              InnerSel = Builder.CreateSelect(CondSI->getFalseValue(),
+                                              TrueSI->getTrueValue(), FalseVal);
+              TrueResult = InnerSel;
+              FalseResult = TrueSI->getFalseValue();
+            } else if (!InvertedInCond && InvertedInTrue) {
+              // select(select C0, true, C1), select(not(C0), A, B), C -> select C0, B, (select C1, A, C)
+              InnerSel = Builder.CreateSelect(CondSI->getFalseValue(),
+                                              TrueSI->getTrueValue(), FalseVal);
+              TrueResult = TrueSI->getFalseValue();
+              FalseResult = InnerSel;
+            } else {
+              // Both inverted (same condition): select(select not(C0), true, C1), select(not(C0), A, B), C
+              // -> select not(C0), A, (select C1, B, C)
+              InnerSel = Builder.CreateSelect(CondSI->getFalseValue(),
+                                              TrueSI->getFalseValue(), FalseVal);
+              TrueResult = TrueSI->getTrueValue();
+              FalseResult = InnerSel;
+            }
+            return SelectInst::Create(CommonCond, TrueResult, FalseResult);
+          }
+        }
     }
   }
   if (SelectInst *FalseSI = dyn_cast<SelectInst>(FalseVal)) {
@@ -3147,6 +3205,68 @@ Instruction *InstCombinerImpl::visitSelectInst(SelectInst &SI) {
         replaceOperand(SI, 2, FalseSI->getFalseValue());
         return &SI;
       }
+      // select(select C0, C1, false), A, select(C0, B, C) ->
+      //   select C0, (select C1, A, B), C
+      // Variations with inverted conditions are handled.
+      if (auto *CondSI = dyn_cast<SelectInst>(CondVal))
+        if (match(CondSI->getFalseValue(), m_Zero()) &&
+            (CondSI->hasOneUse() || FalseSI->hasOneUse())) {
+          Value *InnerCond = CondSI->getCondition();
+          Value *FalseCond = FalseSI->getCondition();
+          Value *CommonCond = nullptr;
+          bool InvertedInCond = false;
+          bool InvertedInFalse = false;
+          if (InnerCond == FalseCond) {
+            CommonCond = InnerCond;
+          } else if (match(InnerCond, m_Not(m_Specific(FalseCond)))) {
+            CommonCond = FalseCond;
+            InvertedInCond = true;
+          } else if (match(FalseCond, m_Not(m_Specific(InnerCond)))) {
+            CommonCond = InnerCond;
+            InvertedInFalse = true;
+          } else {
+            Value *X, *Y;
+            if (match(InnerCond, m_Not(m_Value(X))) &&
+                match(FalseCond, m_Not(m_Value(Y))) && X == Y) {
+              CommonCond = InnerCond;
+            }
+          }
+          if (CommonCond) {
+            Value *InnerSel;
+            Value *TrueResult, *FalseResult;
+            if (!InvertedInCond && !InvertedInFalse) {
+              // select(select C0, C1, false), A, select(C0, B, C) -> select C0, (select C1, A, B), C
+              InnerSel = Builder.CreateSelect(CondSI->getTrueValue(),
+                                              TrueVal,
+                                              FalseSI->getTrueValue());
+              TrueResult = InnerSel;
+              FalseResult = FalseSI->getFalseValue();
+            } else if (InvertedInCond && !InvertedInFalse) {
+              // select(select not(C0), C1, false), A, select(C0, B, C) -> select C0, B, (select C1, A, C)
+              InnerSel = Builder.CreateSelect(CondSI->getTrueValue(),
+                                              TrueVal,
+                                              FalseSI->getFalseValue());
+              TrueResult = FalseSI->getTrueValue();
+              FalseResult = InnerSel;
+            } else if (!InvertedInCond && InvertedInFalse) {
+              // select(select C0, C1, false), A, select(not(C0), B, C) -> select C0, (select C1, A, C), B
+              InnerSel = Builder.CreateSelect(CondSI->getTrueValue(),
+                                              TrueVal,
+                                              FalseSI->getFalseValue());
+              TrueResult = InnerSel;
+              FalseResult = FalseSI->getTrueValue();
+            } else {
+              // Both inverted (same condition): select(select not(C0), C1, false), A, select(not(C0), B, C)
+              // -> select not(C0), (select C1, A, B), C
+              InnerSel = Builder.CreateSelect(CondSI->getTrueValue(),
+                                              TrueVal,
+                                              FalseSI->getTrueValue());
+              TrueResult = InnerSel;
+              FalseResult = FalseSI->getFalseValue();
+            }
+            return SelectInst::Create(CommonCond, TrueResult, FalseResult);
+          }
+        }
     }
   }

